import { readFile } from "node:fs/promises";
import { put } from "@tigrisdata/storage";

const rawTrialId = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();
const bucket = `harbor-interop-${rawTrialId}`
  .toLowerCase()
  .replace(/[^a-z0-9.-]/g, "-");
const body = `{"created_by":"cli","modified_by":"sdk","trial":"${rawTrialId}"}`;

const { data, error } = await put("manifest.json", body, {
  contentType: "application/json",
  config: { bucket },
});

if (error) {
  console.error("upload failed:", error);
  process.exit(1);
}

console.log("uploaded", data);
